sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.loading = false;
    c.filterStatus = c.data.currentFilter || 'pending_approval';
    c.showRejectForm = null;
    c.rejectReason = '';

    c.approve = function(club) {
        if (c.loading) return;
        c.loading = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'approve',
            club_id: club.sys_id
        }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };

    c.reject = function(club) {
        if (c.loading) return;
        if (!c.rejectReason) {
            c.data.errorMsg = 'Please provide a rejection reason.';
            return;
        }
        c.loading = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'reject',
            club_id: club.sys_id,
            reason: c.rejectReason
        }).then(function(r) {
            c.data = r.data;
            c.showRejectForm = null;
            c.rejectReason = '';
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };

    c.toggleRejectForm = function(club) {
        if (c.showRejectForm === club.sys_id) {
            c.showRejectForm = null;
            c.rejectReason = '';
        } else {
            c.showRejectForm = club.sys_id;
            c.rejectReason = '';
        }
    };

    c.applyFilter = function() {
        if (c.loading) return;
        c.loading = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'filter',
            status: c.filterStatus
        }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };
};

sp_widget.css:
.sp-approve-clubs .sp-panel {
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
}
.sp-approve-clubs .sp-panel .panel-heading {
    background: $background-secondary;
    border-bottom: 1px solid $border-tertiary;
    padding: 12px 15px;
}
.sp-approve-clubs .sp-panel .panel-title {
    font-size: 16px;
    font-weight: 600;
    color: $text-color;
    margin: 0;
    line-height: 30px;
}
.sp-approve-clubs .filter-label {
    margin-right: 8px;
    font-weight: 500;
    color: $text-muted;
}
.sp-approve-clubs .sp-panel .table th {
    color: $text-muted;
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid $border-tertiary;
}
.sp-approve-clubs .sp-panel .table td {
    vertical-align: middle;
    color: $text-color;
}
.sp-approve-clubs .text-capitalize {
    text-transform: capitalize;
}
.sp-approve-clubs .empty-state {
    padding: 40px 20px;
}
.sp-approve-clubs .empty-icon {
    font-size: 48px;
    color: $text-muted;
    display: block;
    margin-bottom: 12px;
}
.sp-approve-clubs .reject-form-row {
    background: $state-warning-bg;
}
.sp-approve-clubs .reject-form {
    padding: 10px 0;
}
.sp-approve-clubs .reject-form label {
    font-weight: 600;
    color: $text-color;
    margin-bottom: 6px;
    display: block;
}
.sp-approve-clubs .reject-form textarea {
    margin-bottom: 10px;
}
.sp-approve-clubs .reject-actions {
    display: flex;
    gap: 8px;
}

sp_widget.script:
(function() {
    data.clubs = [];
    data.message = '';
    data.successMsg = '';
    data.errorMsg = '';
    data.isCollegeAdmin = false;
    data.currentFilter = 'pending_approval';

    try {
        var userId = gs.getUserID();

        // Get the current user's college
        var userGr = new GlideRecord('sys_user');
        userGr.setLimit(1);
        if (!userGr.get(userId)) {
            data.message = 'Unable to identify current user.';
            return;
        }

        var collegeId = userGr.getValue('u_college') + '';
        if (!collegeId || collegeId === 'null' || collegeId === '') {
            data.message = 'You are not assigned to a college.';
            return;
        }

        data.isCollegeAdmin = true;

        // Handle approve action
        if (input && input.action === 'approve') {
            var approveGr = new GlideRecord('x_2097092_linq_club');
            approveGr.setLimit(1);
            if (approveGr.get(input.club_id)) {
                // Verify club belongs to this college
                if (approveGr.getValue('college') + '' === collegeId) {
                    approveGr.setValue('status', 'active');
                    approveGr.setValue('approved_on', new GlideDateTime());
                    approveGr.update();
                    data.successMsg = 'Club "' + (approveGr.getValue('name') + '') + '" has been approved.';
                } else {
                    data.errorMsg = 'You do not have permission to approve this club.';
                }
            } else {
                data.errorMsg = 'Club not found.';
            }
        }

        // Handle reject action
        if (input && input.action === 'reject') {
            var rejectGr = new GlideRecord('x_2097092_linq_club');
            rejectGr.setLimit(1);
            if (rejectGr.get(input.club_id)) {
                // Verify club belongs to this college
                if (rejectGr.getValue('college') + '' === collegeId) {
                    rejectGr.setValue('status', 'draft');
                    rejectGr.setValue('rejection_reason', input.reason || '');
                    rejectGr.update();
                    data.successMsg = 'Club "' + (rejectGr.getValue('name') + '') + '" has been rejected.';
                } else {
                    data.errorMsg = 'You do not have permission to reject this club.';
                }
            } else {
                data.errorMsg = 'Club not found.';
            }
        }

        // Determine filter status
        var filterStatus = 'pending_approval';
        if (input && input.action === 'filter' && input.status) {
            filterStatus = input.status;
        }
        data.currentFilter = filterStatus;

        // Get clubs for this college based on filter
        var clubGr = new GlideRecord('x_2097092_linq_club');
        clubGr.addQuery('college', collegeId);
        if (filterStatus !== 'all') {
            clubGr.addQuery('status', filterStatus);
        }
        clubGr.orderByDesc('sys_created_on');
        clubGr.setLimit(100);
        clubGr.query();

        while (clubGr.next()) {
            data.clubs.push({
                sys_id: clubGr.getUniqueValue(),
                name: clubGr.getValue('name') + '',
                category: clubGr.getValue('category') + '',
                created_by: clubGr.getDisplayValue('created_by') + '',
                status: clubGr.getValue('status') + '',
                date_submitted: clubGr.getDisplayValue('sys_created_on') + ''
            });
        }
    } catch (e) {
        gs.error('linq-admin-approve-clubs error: ' + e.message);
        data.errorMsg = 'An error occurred.';
    }
})();
